examples.code:
pl_sdk_config_t cfg = { .transport = PL_TRANSPORT_TCP };
pl_sdk_handle_t sdk;
pl_sdk_init(&cfg, &sdk);

responses.code:
// sdk: PinelabsSdk
println(sdk) // <PinelabsSdk instance>
// sdk.isInitialized == true
// sdk.transportsAvailable == [TCP]

// sdk: PinelabsSdk
print(sdk) // <PinelabsSdk instance>
// sdk.isInitialized == true
// sdk.transportsAvailable == [.tcp]

// sdk: PinelabsSdk
System.out.println(sdk); // <PinelabsSdk instance>
// sdk.isInitialized() == true
// sdk.getTransportsAvailable() == [TCP]

// sdk: PinelabsSdk
console.log(sdk);
// { initialized: true, transportsAvailable: ['TCP'] }

// sdk: pl_sdk_handle_t
// pl_sdk_is_initialized(sdk) == PL_TRUE
// pl_sdk_get_transports(sdk) == PL_TRANSPORT_TCP
